/*
 * rwip_gains.h  --  AUTO-GENERATED by scripts/phase5_export.m  (2026-06-13)
 * Reaction-Wheel Inverted Pendulum -- LQR controller package (ESP32).
 *
 *   State  x = [theta, theta_dot, phi_dot]   (rad, rad/s, rad/s)
 *            theta   : arm angle from UPRIGHT, +CCW (0 = balanced)
 *            phi_dot : wheel speed RELATIVE TO ARM, +CCW
 *   Control tau_cmd = -(K_THETA*theta + K_THETADOT*theta_dot + K_PHIDOT*phi_dot)  [N*m]
 *   then  V = R_OVER_KT*tau_cmd + KE*phi_dot, clamp +/-V_MAX, PWM via DRV8833.
 *
 * Validated in sim @ 200 Hz with gyro bias+noise, motor lag, 10-bit PWM:
 *   steady RMS theta = 0.066 deg, peak wheel = 25.7 rad/s (limit 400).
 * See notes/phase5_handoff.md for the full loop spec.
 */
#ifndef RWIP_GAINS_H
#define RWIP_GAINS_H

/* ---- Control loop ---- */
#define RWIP_LOOP_HZ      200.0f
#define RWIP_LOOP_DT      0.005000f   /* seconds */

/* ---- Discrete LQR gain:  tau_cmd = -(K_THETA*th + K_THETADOT*thd + K_PHIDOT*phid) ---- */
#define RWIP_K_THETA      (-3.907814f)   /* N*m per rad     */
#define RWIP_K_THETADOT   (-0.554054f)   /* N*m per (rad/s) */
#define RWIP_K_PHIDOT     (-0.002694f)   /* N*m per (rad/s) */

/* ---- Brushed-DC motor + driver ---- */
#define RWIP_KT           0.030000f   /* N*m/A  torque const   */
#define RWIP_KE           0.030000f   /* V*s/rad back-EMF const*/
#define RWIP_R            1.000000f   /* ohm  winding resist.  */
#define RWIP_R_OVER_KT    33.333333f   /* V per N*m             */
#define RWIP_V_MAX        12.000f    /* V  (set to MEASURED bus voltage) */
#define RWIP_PWM_BITS     10
#define RWIP_PWM_MAX      1023

/* ---- Sensor fusion ---- */
#define RWIP_COMP_ALPHA   0.9800f   /* complementary filter: th = a*(th+gyro*dt)+(1-a)*th_acc */
#define RWIP_GYRO_CAL_N   400      /* startup gyro-bias samples (~2 s) */

/* ---- Safety / startup limits ---- */
#define RWIP_ENABLE_WIN   0.0873f   /* rad ~5 deg: only enable control within this of upright */
#define RWIP_THETA_GIVEUP 0.5236f   /* rad ~30 deg: cut motor beyond this (fallen) */
#define RWIP_WHEEL_SOFT   350.0f   /* rad/s soft wheel-speed limit */

#endif /* RWIP_GAINS_H */
